// Roving tabindex pattern for custom list
function RovingList({ items }: { items: Item[] }) {
  const [focusedIndex, setFocusedIndex] = useState(0);
  return (
    <ul role="listbox">
      {items.map((item, i) => (
        <li
          key={item.id}
          tabIndex={focusedIndex === i ? 0 : -1}
          role="option"
          aria-selected={focusedIndex === i}
          onKeyDown={(e) => {
            if (e.key === 'ArrowDown') setFocusedIndex(i => Math.min(items.length - 1, i + 1));
            if (e.key === 'ArrowUp') setFocusedIndex(i => Math.max(0, i - 1));
          }}
        >
          {item.label}
        </li>
      ))}
    </ul>
  );
}

