import { useForm, useFieldArray } from 'react-hook-form';

type Form = { items: { name: string; quantity: number }[] };

function OrderForm() {
  const { register, control } = useForm<Form>({
    defaultValues: { items: [{ name: '', quantity: 1 }] }
  });
  const { fields, append, remove } = useFieldArray({ control, name: 'items' });
  return (
    <form>
      {fields.map((field, i) => (
        <div key={field.id}>
          <input {...register(`items.${i}.name`)} />
          <input type="number" {...register(`items.${i}.quantity`)} />
          <button type="button" onClick={() => remove(i)}>Remove</button>
        </div>
      ))}
      <button type="button" onClick={() => append({ name: '', quantity: 1 })}>Add</button>
    </form>
  );
}

import { useEffect } from 'react';
import { useQueryClient } from '@tanstack/react-query';

function useRoutePrefetch(routes: string[]) {
  const qc = useQueryClient();
  useEffect(() => {
    const conn = (navigator as any).connection;
    if (conn?.saveData) return;
    const idle = (window as any).requestIdleCallback ?? ((cb: () => void) => setTimeout(cb, 200));
    idle(() => {
      routes.forEach(route => {
        qc.prefetchQuery({
          queryKey: ['route-data', route],
          queryFn: () => fetch(`/api/${route}-data`).then(r => r.json())
        });
      });
    });
  }, [routes, qc]);
}

